#include <bits/stdc++.h>
using namespace std;
int n,a[100005],sum[1000006],ans[1000006];
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        sum[a[i]]++;
    }
    for(int i=1;i<=1e6;i++)
        if(sum[i])
            for(int j=i;j<=1e6;j+=i)
                ans[j]+=sum[i];
    for(int i=1;i<=n;i++)
        printf("%d\n",ans[a[i]]-1);
    return 0;
}
